          </Button>
        )}
        <h2 className="font-semibold text-lg flex-1" data-testid="text-server-name">
          {server.name}
        </h2>
        <ChevronDown className="w-4 h-4 text-cosmic-gray" />
      </div>

      {/* Channels List */}
      <div className="flex-1 overflow-y-auto p-2 scrollbar-cosmic">
